#!/usr/bin/env python
"""
MABE Bootstrap: Novel Host Generation + Pareto Optimization
============================================================
Extends de novo guest generation to work with novel hosts (MOFs, cages,
synthetic receptors) not in HOST_REGISTRY, via NovelHostSpec.

Also includes Pareto multi-objective optimization (NSGA-II).

Files:
  core/de_novo_generator.py — NovelHostSpec, _score_for_novel_host(),
    generate_for_host() extended to accept NovelHostSpec or str,
    ranking_mode="pareto" on generate_candidates/screen/host
  core/pareto.py — NSGA-II non-dominated sorting + crowding distance
  tests/test_novel_host_generation.py — 26 tests
  tests/test_pareto.py — 40 tests

Supersedes: bootstrap_pareto.py
Requires: bootstrap_novel_materials.py applied first (patches unified_scorer_v2)

Usage:
  python bootstrap_novel_host_gen.py
  python -m pytest tests/test_novel_host_generation.py tests/test_pareto.py tests/test_de_novo_generator.py -v

Expected: 143 passed (26 + 40 + 77), 0 failed
"""
import base64, os, sys, shutil

def write_b64(path, data_b64):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'wb') as f:
        f.write(base64.b64decode(data_b64))
    print(f"  Written: {path} ({os.path.getsize(path)} bytes)")

def main():
    root = os.path.dirname(os.path.abspath(__file__))
    if not os.path.isfile(os.path.join(root, 'core', 'universal_schema.py')):
        root = os.path.dirname(root)
    if not os.path.isfile(os.path.join(root, 'core', 'universal_schema.py')):
        print("ERROR: Run from MABE repo root.")
        sys.exit(1)

    print("MABE Bootstrap: Novel Host Generation + Pareto Optimization")
    print("=" * 60)

    # Backup
    dng = os.path.join(root, 'core', 'de_novo_generator.py')
    bak = dng + '.pre_novel_host_gen.bak'
    if not os.path.isfile(bak):
        shutil.copy2(dng, bak)
        print(f"  Backup: {bak}")

    write_b64(os.path.join(root, "core/de_novo_generator.py"), "")
    write_b64(os.path.join(root, "core/pareto.py"), "")
    write_b64(os.path.join(root, "tests/test_novel_host_generation.py"), "")
    write_b64(os.path.join(root, "tests/test_pareto.py"), "")

    print()
    print("Validation:")
    print("  python -m pytest tests/test_novel_host_generation.py tests/test_pareto.py tests/test_de_novo_generator.py -v")
    print()
    print("Expected: 143 passed (26 novel_host_gen + 40 pareto + 77 de_novo), 0 failed")
    print()
    print("NOTE: Requires bootstrap_novel_materials.py applied first")
    print("      (patches unified_scorer_v2.py for novel host fallback)")

if __name__ == "__main__":
    main()